SELECT A.col1, B.col2
FROM TableA A
INNER JOIN TableB B ON A.id = B.a_id;

SELECT A.col1, B.col2
FROM TableA A
LEFT JOIN TableB B ON A.id = B.a_id;

SELECT A.col1, B.col2
FROM TableA A
RIGHT JOIN TableB B ON A.id = B.a_id;

SELECT A.col1, B.col2
FROM TableA A
FULL OUTER JOIN TableB B ON A.id = B.a_id;

SELECT e.name AS employee, m.name AS manager
FROM employees e
JOIN employees m ON e.manager_id = m.id;

SELECT A.col1, B.col2
FROM TableA A
CROSS JOIN TableB B;

SELECT department, COUNT(*)
FROM employees
GROUP BY department;

SELECT name, salary,
  ROW_NUMBER() OVER (PARTITION BY dept ORDER BY salary DESC) AS rn
FROM employees;

SELECT date, revenue,
  LAG(revenue)  OVER (ORDER BY date) AS prev_revenue
FROM sales;

SELECT date, revenue,
  LEAD(revenue) OVER (ORDER BY date) AS next_revenue
FROM sales;

SELECT date, amount,
  SUM(amount) OVER (ORDER BY date ROWS UNBOUNDED PRECEDING) AS running_total
FROM transactions;

WITH cte AS (
  SELECT department, AVG(salary) AS avg_sal
  FROM employees
  GROUP BY department
)
SELECT * FROM cte WHERE avg_sal > 50000;

WITH
  dept_avg AS (
    SELECT dept_id, AVG(salary) AS avg_sal FROM employees GROUP BY dept_id
  ),
  high_earners AS (
    SELECT * FROM employees WHERE salary > 80000
  )
SELECT h.name, d.avg_sal
FROM high_earners h
JOIN dept_avg d ON h.dept_id = d.dept_id;

SELECT e.name
FROM employees e
WHERE salary > (
  SELECT AVG(salary) FROM employees WHERE dept_id = e.dept_id
);

SELECT name FROM table_a
UNION
SELECT name FROM table_b;

SELECT name FROM table_a
UNION ALL
SELECT name FROM table_b;

INSERT INTO archive_table
SELECT * FROM source_table
WHERE created_at < '2023-01-01';

UPDATE table_name
SET col1 = 'new_value', col2 = col2 + 1
WHERE id = 10;

DELETE FROM orders
WHERE customer_id IN (
  SELECT id FROM customers WHERE active = 0
);

CREATE TABLE users (
  id      INT PRIMARY KEY AUTO_INCREMENT,
  name    VARCHAR(100) NOT NULL,
  email   VARCHAR(255) UNIQUE,
  created TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE orders (
  id      INT PRIMARY KEY AUTO_INCREMENT,
  user_id INT NOT NULL,
  total   DECIMAL(10,2),
  FOREIGN KEY (user_id) REFERENCES users(id)
);

BEGIN;
  UPDATE accounts SET balance = balance - 500 WHERE id = 1;
  UPDATE accounts SET balance = balance + 500 WHERE id = 2;
COMMIT;

BEGIN;
  DELETE FROM orders WHERE customer_id = 9;
ROLLBACK;

SELECT name FROM customers c
WHERE EXISTS (
  SELECT 1 FROM orders o WHERE o.customer_id = c.id
);

SELECT name FROM customers c
WHERE NOT EXISTS (
  SELECT 1 FROM orders o WHERE o.customer_id = c.id
);

SELECT * FROM (
  SELECT *,
    ROW_NUMBER() OVER (PARTITION BY dept ORDER BY salary DESC) AS rn
  FROM employees
) ranked
WHERE rn <= 3;
